  1→import { createHash } from "node:crypto";
  2→import { z } from "zod";
  3→import { createJMAPClient, type JMAPClientWrapper, type Session } from "effect-jmap";
  4→import { Common } from "effect-jmap";
  5→import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
  6→import type { RequestHandlerExtra } from "@modelcontextprotocol/sdk/shared/protocol.js";
  7→import { formatEmailsForLLM } from "./format.js";
  8→import { getCachedSession, setCachedSession } from "./redis.js";
  9→
 10→// Constants
 11→const FASTMAIL_SESSION_ENDPOINT = "https://api.fastmail.com/jmap/session";
 12→
 13→/**
 14→ * Extract bearer token from request headers
 15→ */
 16→function extractBearerToken(extra: RequestHandlerExtra<any, any>): string {
 17→  const headers = extra.requestInfo?.headers;
 18→
 19→  if (!headers) {
 20→    throw new Error(
 21→      "Missing request headers. Ensure Authorization header is set with 'Bearer <token>' format.",
 22→    );
 23→  }
 24→
 25→  // IsomorphicHeaders is Record<string, string | string[] | undefined>
 26→  const authHeader = headers["authorization"] || headers["Authorization"];
 27→
 28→  if (!authHeader || typeof authHeader !== "string" || !authHeader.startsWith("Bearer ")) {
 29→    throw new Error(
 30→      "Missing bearer token. Ensure Authorization header is set with 'Bearer <token>' format.",
 31→    );
 32→  }
 33→
 34→  return authHeader.substring(7);
 35→}
 36→
 37→function hashToken(token: string): string {
 38→  return createHash("sha256").update(token).digest("hex").slice(0, 16);
 39→}
 40→
 41→/**
 42→ * Create a JMAP client from the bearer token in the request.
 43→ * Uses Redis to cache the JMAP session, avoiding an HTTP round-trip
 44→ * to the session endpoint on every tool call.
 45→ */
 46→async function getClient(extra: RequestHandlerExtra<any, any>): Promise<JMAPClientWrapper> {
 47→  const bearerToken = extractBearerToken(extra);
 48→  const tokenHash = hashToken(bearerToken);
 49→
 50→  // Try to use cached session from Redis
 51→  const cached = await getCachedSession(tokenHash).catch(() => null);
 52→  if (cached) {
 53→    const session: Session = JSON.parse(cached.json);
 54→    return createJMAPClient(FASTMAIL_SESSION_ENDPOINT, bearerToken, { session });
 55→  }
 56→
 57→  // No cache — create client (fetches session from Fastmail)
 58→  const client = await createJMAPClient(FASTMAIL_SESSION_ENDPOINT, bearerToken);
 59→
 60→  // Cache the session in Redis for subsequent requests
 61→  await setCachedSession(tokenHash, {
 62→    accountId: client.accountId,
 63→    json: JSON.stringify(client.session),
 64→  }).catch(() => {}); // Don't fail the request if Redis is down
 65→
 66→  return client;
 67→}
