 69→// Zod schemas for validation
 70→export const EmailQuerySchema = z.object({
 71→  accountId: z.string().optional(),
 72→  mailboxId: z.string().optional(),
 73→  limit: z.number().min(1).max(100).default(10),
 74→  from: z.string().optional(),
 75→  to: z.string().optional(),
 76→  subject: z.string().optional(),
 77→  hasKeyword: z.string().optional(),
 78→  notKeyword: z.string().optional(),
 79→  before: z.string().optional(),
 80→  after: z.string().optional(),
 81→  sort: z.enum(["receivedAt", "sentAt", "subject", "from"]).default("receivedAt"),
 82→  ascending: z.boolean().default(false),
 83→});
 84→
 85→export const EmailGetSchema = z.object({
 86→  accountId: z.string().optional(),
 87→  emailIds: z.array(z.string()).min(1).max(50),
 88→  properties: z.array(z.string()).optional(),
 89→  fetchTextBodyValues: z.boolean().optional(),
 90→  fetchHTMLBodyValues: z.boolean().optional(),
 91→  fetchAllBodyValues: z.boolean().optional(),
 92→  maxBodyValueBytes: z.number().optional(),
 93→});
 94→
 95→export const EmailSendSchema = z.object({
 96→  to: z.string().email(),
 97→  subject: z.string(),
 98→  body: z.string(),
 99→  htmlBody: z.string().optional(),
100→  identityId: z.string().optional(),
101→});
102→
103→const FLAG_VALUES = [
104→  "read",
105→  "unread",
106→  "flagged",
107→  "unflagged",
108→  "answered",
109→  "unanswered",
110→  "draft",
111→  "undraft",
112→] as const;
113→
114→export const EmailSetSchema = z.object({
115→  accountId: z.string().optional(),
116→  emailIds: z.array(z.string()).min(1).max(50),
117→  mailboxId: z
118→    .string()
119→    .optional()
120→    .describe(
121→      "Target mailbox ID or well-known role: 'trash', 'archive', 'inbox', 'drafts', 'junk', 'sent'",
122→    ),
123→  flags: z
124→    .array(z.enum(FLAG_VALUES))
125→    .min(1)
126→    .optional()
127→    .describe(
128→      "Flags to set: 'read'/'unread', 'flagged'/'unflagged', 'answered'/'unanswered', 'draft'/'undraft'",
129→    ),
130→});
131→
132→export type EmailSetArgs = z.infer<typeof EmailSetSchema>;
133→
134→// Flag name → JMAP keyword mapping
135→const FLAG_TO_KEYWORD: Record<string, { keyword: string; value: boolean }> = {
136→  read: { keyword: "$seen", value: true },
137→  unread: { keyword: "$seen", value: false },
138→  flagged: { keyword: "$flagged", value: true },
139→  unflagged: { keyword: "$flagged", value: false },
140→  answered: { keyword: "$answered", value: true },
141→  unanswered: { keyword: "$answered", value: false },
142→  draft: { keyword: "$draft", value: true },
143→  undraft: { keyword: "$draft", value: false },
144→};
145→
146→function resolveFlags(flags: readonly string[]): {
147→  markRead?: boolean;
148→  setFlagged?: boolean;
149→  keywordsToAdd: string[];
150→  keywordsToRemove: string[];
151→} {
152→  const result: ReturnType<typeof resolveFlags> = {
153→    keywordsToAdd: [],
154→    keywordsToRemove: [],
155→  };
156→
157→  const seen = new Map<string, string>(); // keyword → flag name that set it
158→
159→  for (const flag of flags) {
160→    const mapping = FLAG_TO_KEYWORD[flag];
161→    if (!mapping) throw new Error(`Unknown flag: '${flag}'`);
162→
163→    const prev = seen.get(mapping.keyword);
164→    if (prev !== undefined && prev !== flag) {
165→      throw new Error(`Contradictory flags: '${prev}' and '${flag}'`);
166→    }
167→    seen.set(mapping.keyword, flag);
168→
169→    if (mapping.keyword === "$seen") {
170→      result.markRead = mapping.value;
171→    } else if (mapping.keyword === "$flagged") {
172→      result.setFlagged = mapping.value;
173→    } else if (mapping.value) {
174→      result.keywordsToAdd.push(mapping.keyword);
175→    } else {
176→      result.keywordsToRemove.push(mapping.keyword);
177→    }
178→  }
179→
180→  return result;
181→}
182→
183→// Type exports
184→export type EmailQueryArgs = z.infer<typeof EmailQuerySchema>;
185→export type EmailGetArgs = z.infer<typeof EmailGetSchema>;
186→export type EmailSendArgs = z.infer<typeof EmailSendSchema>;
