188→/**
189→ * Helper function to upload a blob (RFC 5322 email message) to JMAP server
190→ */
191→async function uploadBlob(
192→  emailMessage: string,
193→  bearerToken: string,
194→  client: JMAPClientWrapper,
195→): Promise<{ blobId: string; size: number; type: string }> {
196→  const uploadUrl = client.session.uploadUrl.replace("{accountId}", client.accountId);
197→
198→  const response = await fetch(uploadUrl, {
199→    method: "POST",
200→    headers: {
201→      Authorization: `Bearer ${bearerToken}`,
202→      "Content-Type": "message/rfc822",
203→    },
204→    body: emailMessage,
205→  });
206→
207→  if (!response.ok) {
208→    throw new Error(`Upload failed: HTTP ${response.status}`);
209→  }
210→
211→  const result = (await response.json()) as {
212→    blobId: string;
213→    size: number;
214→    type: string;
215→  };
216→
217→  return {
218→    blobId: result.blobId,
219→    size: result.size,
220→    type: result.type,
221→  };
222→}
