224→/**
225→ * Generate a unique MIME boundary string
226→ */
227→function generateMimeBoundary(): string {
228→  const timestamp = Date.now();
229→  const random = Math.random().toString(36).substring(2, 15);
230→  return `----=_Part_${timestamp}_${random}`;
231→}
232→
233→/**
234→ * Build RFC 5322 email message
235→ */
236→function buildEmailMessage(params: {
237→  identity: { name?: string; email: string };
238→  to: string;
239→  subject: string;
240→  body: string;
241→  htmlBody?: string;
242→}): string {
243→  const { identity, to, subject, body, htmlBody } = params;
244→
245→  const messageId = `<${Date.now()}.${Math.random().toString(36).substring(2)}@fastmail-mcp>`;
246→
247→  const fromHeader = identity.name
248→    ? `From: "${identity.name}" <${identity.email}>`
249→    : `From: ${identity.email}`;
250→
251→  const normalizedBody = body.replace(/\r?\n/g, "\r\n");
252→  const normalizedHtmlBody = htmlBody?.replace(/\r?\n/g, "\r\n");
253→
254→  const commonHeaders = [
255→    `Message-ID: ${messageId}`,
256→    `Date: ${new Date().toUTCString()}`,
257→    fromHeader,
258→    `To: ${to}`,
259→    `Subject: ${subject}`,
260→    `MIME-Version: 1.0`,
261→  ];
262→
263→  if (!normalizedHtmlBody) {
264→    return [
265→      ...commonHeaders,
266→      `Content-Type: text/plain; charset=utf-8`,
267→      `Content-Transfer-Encoding: 8bit`,
268→      ``,
269→      normalizedBody,
270→    ].join("\r\n");
271→  }
272→
273→  const boundary = generateMimeBoundary();
274→
275→  return [
276→    ...commonHeaders,
277→    `Content-Type: multipart/alternative; boundary="${boundary}"`,
278→    ``,
279→    `This is a multi-part message in MIME format.`,
280→    ``,
281→    `--${boundary}`,
282→    `Content-Type: text/plain; charset=utf-8`,
283→    `Content-Transfer-Encoding: 8bit`,
284→    ``,
285→    normalizedBody,
286→    ``,
287→    `--${boundary}`,
288→    `Content-Type: text/html; charset=utf-8`,
289→    `Content-Transfer-Encoding: 8bit`,
290→    ``,
291→    normalizedHtmlBody,
292→    ``,
293→    `--${boundary}--`,
294→  ].join("\r\n");
295→}
