297→/**
298→ * Tool: Get all mailboxes
299→ */
300→export async function mailboxGet(extra: RequestHandlerExtra<any, any>): Promise<any> {
301→  const client = await getClient(extra);
302→  return await client.mailbox.getAll();
303→}
