305→/**
306→ * Tool: Get emails by ID
307→ */
308→export async function emailGet(
309→  args: EmailGetArgs,
310→  extra: RequestHandlerExtra<any, any>,
311→): Promise<any> {
312→  const client = await getClient(extra);
313→  const accountId = args.accountId || client.accountId;
314→
315→  const emailResult = await client.email.get({
316→    accountId: accountId,
317→    ids: args.emailIds.map((id) => Common.createId(id)),
318→    properties: args.properties,
319→    fetchTextBodyValues: args.fetchTextBodyValues,
320→    fetchHTMLBodyValues: args.fetchHTMLBodyValues,
321→    fetchAllBodyValues: args.fetchAllBodyValues ?? true,
322→    maxBodyValueBytes: args.maxBodyValueBytes
323→      ? Common.createUnsignedInt(args.maxBodyValueBytes)
324→      : undefined,
325→  });
326→
327→  // Format emails as clean text for LLM consumption
328→  return formatEmailsForLLM(emailResult.list as any[]);
329→}
