331→/**
332→ * Tool: Query emails
333→ */
334→export async function emailQuery(
335→  args: EmailQueryArgs,
336→  extra: RequestHandlerExtra<any, any>,
337→): Promise<any> {
338→  const client = await getClient(extra);
339→  const accountId = args.accountId || client.accountId;
340→
341→  let filter: any = {};
342→  if (args.mailboxId) filter.inMailbox = args.mailboxId;
343→  if (args.from) filter.from = args.from;
344→  if (args.to) filter.to = args.to;
345→  if (args.subject) filter.subject = args.subject;
346→  if (args.hasKeyword) filter.hasKeyword = args.hasKeyword;
347→  if (args.notKeyword) filter.notKeyword = args.notKeyword;
348→  if (args.before) filter.before = args.before;
349→  if (args.after) filter.after = args.after;
350→
351→  const sort = [{ property: args.sort, isAscending: args.ascending }];
352→
353→  return await client.email.query({
354→    accountId,
355→    filter: Object.keys(filter).length > 0 ? filter : undefined,
356→    sort,
357→    limit: Common.createUnsignedInt(args.limit),
358→  });
359→}
