361→/**
362→ * Tool: Send email
363→ */
364→export async function emailSend(
365→  args: EmailSendArgs,
366→  extra: RequestHandlerExtra<any, any>,
367→): Promise<any> {
368→  const bearerToken = extractBearerToken(extra);
369→  const client = await createJMAPClient(FASTMAIL_SESSION_ENDPOINT, bearerToken);
370→  const accountId = client.accountId;
371→
372→  // Get identity
373→  let identity;
374→
375→  if (args.identityId) {
376→    const result = await client.identity.get({
377→      accountId,
378→      ids: [Common.createId(args.identityId)],
379→    });
380→    if (!result.list[0]) {
381→      throw new Error("Identity not found");
382→    }
383→    identity = result.list[0];
384→  } else {
385→    identity = await client.identity.getDefault();
386→  }
387→
388→  const identityId = identity.id;
389→
390→  // Build RFC 5322 email message
391→  const emailMessage = buildEmailMessage({
392→    identity,
393→    to: args.to,
394→    subject: args.subject,
395→    body: args.body,
396→    htmlBody: args.htmlBody,
397→  });
398→
399→  // Upload the email message as a blob
400→  const uploadResult = await uploadBlob(emailMessage, bearerToken, client);
401→
402→  // Find drafts mailbox
403→  const mailboxes = await client.mailbox.getAll();
404→  const draftsMailbox = mailboxes.find((mb) => mb.role === "drafts");
405→
406→  if (!draftsMailbox) {
407→    throw new Error("Drafts mailbox not found");
408→  }
409→
410→  // Import the email
411→  const importResult = await client.email.import({
412→    accountId,
413→    emails: {
414→      [`draft-${Date.now()}`]: {
415→        blobId: uploadResult.blobId,
416→        mailboxIds: { [draftsMailbox.id]: true },
417→        keywords: { $draft: true },
418→      },
419→    },
420→  });
421→
422→  if (!importResult.created) {
423→    if (importResult.notCreated) {
424→      const errors = Object.entries(importResult.notCreated).map(
425→        ([key, error]) => `${key}: ${JSON.stringify(error)}`,
426→      );
427→      throw new Error(`Failed to import email: ${errors.join(", ")}`);
428→    }
429→    throw new Error("Failed to import email: no created field in response");
430→  }
431→
432→  const createdEmails = Object.values(importResult.created);
433→  if (createdEmails.length === 0) {
434→    throw new Error("No email was created");
435→  }
436→
437→  const emailId = createdEmails[0].id;
438→
439→  // Send the email
440→  const submission = await client.submission.send(Common.createId(identityId), emailId);
441→
442→  return {
443→    id: submission.id,
444→    sendAt: submission.sendAt || "immediately",
445→  };
446→}
