448→const WELL_KNOWN_ROLES = ["trash", "archive", "inbox", "drafts", "junk", "sent"] as const;
449→
450→/**
451→ * Tool: Update emails — move to mailbox and/or set flags
452→ */
453→export async function emailSet(
454→  args: EmailSetArgs,
455→  extra: RequestHandlerExtra<any, any>,
456→): Promise<any> {
457→  if (!args.mailboxId && !args.flags) {
458→    throw new Error("At least one of 'mailboxId' or 'flags' must be provided");
459→  }
460→
461→  const client = await getClient(extra);
462→  const accountId = args.accountId || client.accountId;
463→
464→  const ids = args.emailIds.map((id) => Common.createId(id));
465→  let targetMailboxId: string | undefined;
466→  const results: Record<string, unknown> = {};
467→
468→  // Move to mailbox
469→  if (args.mailboxId) {
470→    const isRole = WELL_KNOWN_ROLES.includes(args.mailboxId as any);
471→
472→    if (isRole) {
473→      const mailboxes = await client.mailbox.findByRole(args.mailboxId as any);
474→      if (mailboxes.length === 0) {
475→        throw new Error(`No mailbox found with role '${args.mailboxId}'`);
476→      }
477→      targetMailboxId = mailboxes[0].id;
478→    } else {
479→      targetMailboxId = args.mailboxId;
480→    }
481→
482→    const update: Record<string, { mailboxIds: Record<string, boolean> }> = {};
483→    for (const emailId of args.emailIds) {
484→      update[Common.createId(emailId) as string] = {
485→        mailboxIds: { [Common.createId(targetMailboxId) as string]: true },
486→      };
487→    }
488→
489→    const moveResult = await client.email.set({ accountId, update: update as any });
490→    const movedCount = moveResult.updated ? Object.keys(moveResult.updated).length : 0;
491→    results.moved = movedCount;
492→    results.targetMailboxId = targetMailboxId;
493→    if (moveResult.notUpdated && Object.keys(moveResult.notUpdated).length > 0) {
494→      results.notUpdated = moveResult.notUpdated;
495→    }
496→  }
497→
498→  // Set flags
499→  if (args.flags) {
500→    const resolved = resolveFlags(args.flags);
501→
502→    if (resolved.markRead !== undefined) {
503→      await client.email.markRead(ids, resolved.markRead, accountId);
504→    }
505→    if (resolved.setFlagged !== undefined) {
506→      await client.email.flag(ids, resolved.setFlagged, accountId);
507→    }
508→    if (resolved.keywordsToAdd.length > 0 || resolved.keywordsToRemove.length > 0) {
509→      await client.email.updateKeywords(
510→        ids,
511→        resolved.keywordsToAdd,
512→        resolved.keywordsToRemove,
513→        accountId,
514→      );
515→    }
516→
517→    results.flags = args.flags;
518→    results.flagsUpdated = args.emailIds.length;
519→  }
520→
521→  return results;
522→}
