525→export const toolDefinitions = {
526→  mailbox_get: {
527→    description: "Get all mailboxes using JMAP Mailbox/get method",
528→    parameters: z.object({}),
529→  },
530→  email_get: {
531→    description:
532→      "Get specific emails by their IDs. Returns formatted text optimized for LLM consumption.",
533→    parameters: EmailGetSchema,
534→  },
535→  email_query: {
536→    description: "Query emails with filters and sorting",
537→    parameters: EmailQuerySchema,
538→  },
539→  email_send: {
540→    description:
541→      "Send an email via Fastmail. Supports plain text, HTML, or multipart/alternative (both) emails.",
542→    parameters: EmailSendSchema,
