551→/**
552→ * Register all tools with the MCP server
553→ */
554→export function registerTools(server: McpServer) {
555→  // Tool: Get all mailboxes
556→  server.registerTool(
557→    "mailbox_get",
558→    {
559→      description: "Get all mailboxes using JMAP Mailbox/get method",
560→      inputSchema: z.object({}),
561→    },
562→    async (_input, extra) => {
563→      try {
564→        const result = await mailboxGet(extra);
565→        return {
566→          content: [{ type: "text", text: JSON.stringify(result, null, 2) }],
567→        };
568→      } catch (error) {
569→        return {
570→          content: [
571→            {
572→              type: "text",
573→              text: `Error: ${error instanceof Error ? error.message : String(error)}`,
574→            },
575→          ],
576→          isError: true,
577→        };
578→      }
579→    },
580→  );
581→
582→  // Tool: Get emails by ID
583→  server.registerTool(
584→    "email_get",
585→    {
586→      description:
587→        "Get specific emails by their IDs. Returns formatted text optimized for LLM consumption.",
588→      inputSchema: EmailGetSchema,
589→    },
590→    async (args, extra) => {
591→      try {
592→        const formattedEmails = await emailGet(args, extra);
593→        return {
594→          content: [{ type: "text", text: formattedEmails }],
595→        };
596→      } catch (error) {
597→        return {
598→          content: [
599→            {
600→              type: "text",
601→              text: `Error: ${error instanceof Error ? error.message : String(error)}`,
602→            },
603→          ],
604→          isError: true,
605→        };
606→      }
607→    },
608→  );
609→
610→  // Tool: Query emails
611→  server.registerTool(
612→    "email_query",
613→    {
614→      description: "Query emails with filters and sorting",
615→      inputSchema: EmailQuerySchema,
616→    },
617→    async (args, extra) => {
618→      try {
619→        const result = await emailQuery(args, extra);
620→        return {
621→          content: [{ type: "text", text: JSON.stringify(result, null, 2) }],
622→        };
623→      } catch (error) {
624→        return {
625→          content: [
626→            {
627→              type: "text",
628→              text: `Error: ${error instanceof Error ? error.message : String(error)}`,
629→            },
630→          ],
631→          isError: true,
632→        };
633→      }
634→    },
635→  );
636→
637→  // Tool: Send email
638→  server.registerTool(
639→    "email_send",
640→    {
641→      description:
642→        "Send an email via Fastmail. Supports plain text, HTML, or multipart/alternative (both) emails.",
643→      inputSchema: EmailSendSchema,
644→    },
645→    async (args, extra) => {
646→      try {
647→        const result = await emailSend(args, extra);
648→        return {
649→          content: [
650→            {
651→              type: "text",
652→              text: `Email sent successfully!\nSubmission ID: ${result.id}\nSent at: ${result.sendAt}`,
653→            },
654→          ],
655→        };
656→      } catch (error) {
657→        return {
658→          content: [
659→            {
660→              type: "text",
661→              text: `Error: ${error instanceof Error ? error.message : String(error)}`,
662→            },
663→          ],
664→          isError: true,
665→        };
666→      }
667→    },
668→  );
669→
670→  // Tool: Update emails (move and/or set flags)
671→  server.registerTool(
672→    "email_set",
673→    {
674→      description:
675→        "Update emails: move to a mailbox and/or set flags. For mailbox, use well-known names: 'trash' (delete), 'archive', 'inbox', 'junk', 'drafts', 'sent', or a mailbox ID. For flags: 'read'/'unread', 'flagged'/'unflagged', 'answered'/'unanswered', 'draft'/'undraft'.",
676→      inputSchema: EmailSetSchema,
677→    },
678→    async (args, extra) => {
679→      try {
680→        const result = await emailSet(args, extra);
681→        return {
682→          content: [{ type: "text", text: JSON.stringify(result, null, 2) }],
