  3→/**
  4→ * Unescape JSON string escape sequences commonly found in JMAP body values.
  5→ * JMAP returns HTML body content as JSON strings, so literal \n, \", \t etc.
  6→ * must be converted to their real characters before HTML parsing.
  7→ */
  8→function unescapeJsonString(str: string): string {
  9→  return str
 10→    .replace(/\\n/g, "\n")
 11→    .replace(/\\r/g, "\r")
 12→    .replace(/\\t/g, "\t")
 13→    .replace(/\\"/g, '"')
 14→    .replace(/\\\\/g, "\\");
 15→}
 16→
 17→/**
 18→ * Sanitize email HTML using cheerio.
 19→ * Strips scripts, styles, tracking pixels, hidden elements,
 20→ * MSO conditional comments, and layout tables that produce noise.
 21→ */
 22→export function sanitizeEmailHtml(html: string): string {
 23→  // Unescape JSON string escapes (JMAP body values are JSON strings)
 24→  html = unescapeJsonString(html);
 25→
 26→  // Strip MSO conditional comments: <!--[if ...]>...<![endif]-->
 27→  // These contain <style> blocks and markup only relevant to Outlook
 28→  html = html.replace(/<!--\[if[^\]]*\]>[\s\S]*?<!\[endif\]-->/gi, "");
 29→  // Also handle the <![if !mso]> variant (non-comment form)
 30→  html = html.replace(/<!\[if[^\]]*\]>/gi, "");
 31→  html = html.replace(/<!--<!\[endif\]-->/gi, "");
 32→
 33→  const $ = load(html);
 34→
 35→  // Remove elements that should never appear in email text content
 36→  $("script, style, noscript, iframe, object, embed, applet").remove();
 37→
 38→  // Remove <head> content (meta tags, title) that leaks into output
 39→  $("head").remove();
 40→
 41→  // Remove hidden elements
 42→  $("[style*='display:none'], [style*='display: none']").remove();
 43→  $("[style*='visibility:hidden'], [style*='visibility: hidden']").remove();
 44→  $("[hidden]").remove();
 45→
 46→  // Remove tracking pixels (1x1 images or images with no meaningful src)
 47→  $("img").each(function () {
 48→    const width = $(this).attr("width");
 49→    const height = $(this).attr("height");
 50→    if ((width === "1" && height === "1") || (width === "0" && height === "0")) {
 51→      $(this).remove();
 52→    }
 53→  });
 54→
 55→  // Unwrap layout tables, keeping only data tables.
 56→  // In email HTML, tables are almost exclusively used for layout.
 57→  // A data table has <th> elements; everything else is layout.
 58→  // Must iterate innermost-first so nested layout tables unwrap correctly.
 59→  let changed = true;
 60→  while (changed) {
 61→    changed = false;
 62→    $("table").each(function () {
 63→      // Skip tables that contain nested tables — process inner ones first
 64→      if ($(this).find("table").length > 0) return;
 65→
 66→      const isDataTable =
 67→        $(this).find("th").length > 0 ||
 68→        $(this).attr("role") === "grid" ||
 69→        $(this).attr("role") === "table";
 70→
 71→      if (!isDataTable) {
 72→        // Replace the table with the contents of its cells
 73→        const cellContents: string[] = [];
 74→        $(this)
 75→          .find("td, th")
 76→          .each(function () {
 77→            const inner = $(this).html()?.trim();
 78→            if (inner) cellContents.push(inner);
 79→          });
 80→        $(this).replaceWith(cellContents.join("\n"));
 81→        changed = true;
 82→      }
 83→    });
 84→  }
 85→
 86→  // Remove all style attributes — they add noise and no value for text extraction
 87→  $("[style]").removeAttr("style");
 88→
 89→  // Remove presentational attributes that add no text value
 90→  $("[class]").removeAttr("class");
 91→  $("[bgcolor]").removeAttr("bgcolor");
 92→  $("[align]").removeAttr("align");
 93→  $("[valign]").removeAttr("valign");
 94→  $("[cellpadding]").removeAttr("cellpadding");
 95→  $("[cellspacing]").removeAttr("cellspacing");
 96→  $("[border]").removeAttr("border");
 97→
 98→  // Clean up leftover table wrapper elements
 99→  $("tbody, thead, tfoot").each(function () {
100→    if ($(this).closest("table").length === 0) {
101→      $(this).replaceWith($(this).html() || "");
102→    }
103→  });
104→  $("tr").each(function () {
105→    if ($(this).closest("table").length === 0) {
106→      $(this).replaceWith($(this).html() || "");
107→    }
108→  });
109→  $("td, th").each(function () {
110→    if ($(this).closest("table").length === 0) {
111→      $(this).replaceWith($(this).html() || "");
112→    }
113→  });
114→  $("center").each(function () {
115→    $(this).replaceWith($(this).html() || "");
116→  });
117→
118→  // Strip HTML comments
119→  let result = $.html();
120→  result = result.replace(/<!--[\s\S]*?-->/g, "");
121→
122→  // Collapse runs of blank lines into a single blank line
123→  result = result.replace(/\n{3,}/g, "\n\n");
124→
125→  return result.trim();
126→}
