128→/**
129→ * Get the body content from an email.
130→ * Prefers htmlBody (sanitized) for consistent output.
131→ * Falls back to textBody for plain-text emails.
132→ */
133→function getEmailBody(email: any): string {
134→  if (!email.bodyValues) return "";
135→
136→  // Use htmlBody, sanitized for LLM consumption
137→  if (email.htmlBody && email.htmlBody.length > 0) {
138→    const htmlParts: string[] = [];
139→    for (const part of email.htmlBody) {
140→      const body = email.bodyValues[part.partId];
141→      if (body?.value) {
142→        htmlParts.push(body.value);
143→      }
144→    }
145→    if (htmlParts.length > 0) {
146→      return sanitizeEmailHtml(htmlParts.join("\n"));
147→    }
148→  }
149→
150→  // Fall back to textBody if no htmlBody
151→  if (email.textBody && email.textBody.length > 0) {
152→    const textParts: string[] = [];
153→    for (const part of email.textBody) {
154→      const body = email.bodyValues[part.partId];
155→      if (body?.value) {
156→        textParts.push(body.value);
157→      }
158→    }
159→    if (textParts.length > 0) {
160→      return textParts.join("\n").trim();
161→    }
162→  }
163→
164→  return "";
165→}
