167→/**
168→ * Escape XML attribute value
169→ */
170→function escapeXmlAttr(str: string): string {
171→  return str
172→    .replace(/&/g, "&amp;")
173→    .replace(/"/g, "&quot;")
174→    .replace(/</g, "&lt;")
175→    .replace(/>/g, "&gt;");
176→}
177→
178→/**
179→ * Escape XML text content
180→ */
181→function escapeXmlText(str: string): string {
182→  return str.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
183→}
184→
185→/**
186→ * Format address list as XML nodes
187→ */
188→function formatAddressNodes(
189→  addresses: Array<{ name?: string; email: string }> | undefined,
190→  tagName: string,
191→): string | null {
192→  if (!addresses || addresses.length === 0) return null;
193→
194→  const addressTags = addresses.map((addr) => {
195→    const nameAttr = addr.name ? ` name="${escapeXmlAttr(addr.name)}"` : "";
196→    return `    <address${nameAttr} email="${escapeXmlAttr(addr.email)}" />`;
197→  });
198→
199→  return `  <${tagName}>\n${addressTags.join("\n")}\n  </${tagName}>`;
200→}
201→
202→/**
203→ * Format a single email as XML
204→ */
205→function formatEmailXml(email: any): string {
206→  const lines: string[] = [];
207→
208→  // Email opening tag with core attributes
209→  const attrs: string[] = [`id="${escapeXmlAttr(email.id)}"`];
210→
211→  if (email.receivedAt) {
212→    attrs.push(`date="${new Date(email.receivedAt).toISOString()}"`);
213→  } else if (email.sentAt) {
214→    attrs.push(`date="${new Date(email.sentAt).toISOString()}"`);
215→  }
216→
217→  const flags: string[] = [];
218→  if (!email.keywords?.$seen) flags.push("unread");
219→  if (email.keywords?.$flagged) flags.push("flagged");
220→  if (email.keywords?.$answered) flags.push("replied");
221→  if (email.keywords?.$draft) flags.push("draft");
222→  if (flags.length > 0) attrs.push(`status="${flags.join(", ")}"`);
223→
224→  if (email.hasAttachment) attrs.push(`attachments="yes"`);
225→
226→  lines.push(`<email ${attrs.join(" ")}>`);
227→
228→  // Address fields per RFC 8621
229→  const fromNodes = formatAddressNodes(email.from, "from");
230→  if (fromNodes) lines.push(fromNodes);
231→
232→  const toNodes = formatAddressNodes(email.to, "to");
233→  if (toNodes) lines.push(toNodes);
234→
235→  const ccNodes = formatAddressNodes(email.cc, "cc");
236→  if (ccNodes) lines.push(ccNodes);
237→
238→  const bccNodes = formatAddressNodes(email.bcc, "bcc");
239→  if (bccNodes) lines.push(bccNodes);
240→
241→  const replyToNodes = formatAddressNodes(email.replyTo, "reply_to");
242→  if (replyToNodes) lines.push(replyToNodes);
243→
244→  const senderNodes = formatAddressNodes(email.sender, "sender");
245→  if (senderNodes) lines.push(senderNodes);
246→
247→  // Subject
248→  if (email.subject) {
249→    lines.push(`  <subject>${escapeXmlText(email.subject)}</subject>`);
250→  }
251→
252→  // Body
253→  const body = getEmailBody(email);
254→  lines.push(`  <body>\n${body}\n  </body>`);
255→
256→  lines.push("</email>");
257→
258→  return lines.join("\n");
259→}
260→
261→/**
262→ * Format emails into XML structure grouped by thread.
263→ * Sanitizes HTML bodies for cleaner LLM consumption.
264→ */
265→export function formatEmailsForLLM(emails: any[]): string {
266→  // Group emails by threadId
267→  const threads = new Map<string, any[]>();
268→
269→  for (const email of emails) {
270→    const threadId = email.threadId || email.id;
271→    if (!threads.has(threadId)) {
272→      threads.set(threadId, []);
273→    }
274→    threads.get(threadId)!.push(email);
275→  }
276→
277→  // Sort emails within each thread by date (oldest first)
278→  for (const threadEmails of threads.values()) {
279→    threadEmails.sort((a, b) => {
280→      const dateA = new Date(a.receivedAt || a.sentAt || 0).getTime();
281→      const dateB = new Date(b.receivedAt || b.sentAt || 0).getTime();
282→      return dateA - dateB;
283→    });
284→  }
285→
286→  // Format each thread
287→  const threadOutputs: string[] = [];
288→
289→  for (const [threadId, threadEmails] of threads) {
290→    const emailTags = threadEmails.map(formatEmailXml);
291→    threadOutputs.push(`<thread id="${threadId}">\n${emailTags.join("\n")}\n</thread>`);
292→  }
293→
294→  return threadOutputs.join("\n\n");
295→}
